module RefModule (
    input clk,
    input rst,
    output [11:0] q
);

    reg [11:0] obf_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            obf_q_reg <= 12'b000000000000;
        else
            obf_q_reg <= obf_q_reg + 2;
    end

    assign q = obf_q_reg;

endmodule
